VALUES
  ('retired-d0d1b9a2-moex-00350', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '近10年來我國中央政府總預算歲出中，何項政事別支出金額最高？', '["國防支出", "教育科學文化支出", "經濟發展支出", "社會福利支出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00351', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '假設某財貨之需求曲線無彈性、供給曲線正斜率，該財貨原均衡價格為20元，均衡交易量為100 單位。政府對該財貨課徵每單位2元的從量稅，下列敘述何者正確？', '["供給者稅後每單位取得18元", "消費者稅後每單位支付22元", "稅後均衡交易量減少為80單位", "政府稅收180元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00352', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '依據哈柏格對部分要素稅一般均衡分析之說明，若僅對公司部門之資本要素報酬課稅，引起資本 要素流向非公司部門之經濟行為改變，下列敘述何者錯誤？', '["係由公司部門與非公司部門之資本報酬差異引發經濟行為改變", "要素替代效果使非公司部門資本使用量增加", "產量效果使公司部門資本使用量減少", "最終效果將使非公司部門之資本稅後邊際報酬高於公司部門"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00353', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '假設投資人為風險厭惡者，總資產固定，分配投資於無風險資產與風險性資產之間，前者風險與 報酬率均為零，後者之資本報酬率可能為正或負，且為常態分配的隨機變數。假設政府對投資報 酬課徵比例所得稅，稅率為 t，投資損失可完全扣除，投資者稅前選擇之資產組合非角解。下列 敘述何者正確？', '["投資者稅後總預期報酬率增加", "投資者稅後總預期風險增加", "投資者稅後選擇風險性資產投資數額增加", "投資風險轉為全由政府承擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00354', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '若某獨占市場的財貨之需求曲線為負斜率直線，邊際成本線為正斜率直線，政府對其課徵每單位 t元的從量稅，下列敘述何者錯誤？', '["獨占廠商面對之稅前與稅後平均收入曲線垂直差距為政府每單位從量稅金額", "獨占廠商面對之稅前與稅後邊際收入曲線為平行左移", "稅後均衡交易數量較課稅前減少", "由於市場獨占，廠商可將從量稅完全轉嫁給消費者負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00355', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '假設政府以消費稅取代所得稅，可能使個體的儲蓄增加、提高社會資本累積，是基於什麼原因？', '["物價下跌使消費者的實質所得增加，而使儲蓄量增加的所得效果", "向高所得者收稅後透過社會福利制度移轉給低所得者的重分配效果", "儲蓄者在勞動階段稅負減少、稅負延後到退休消費時繳納的稅負延後效果", "個體進行儲蓄選擇時，實質利率與預期通膨率無關的費雪效果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00356', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '下列有關資本出口中立性（capital-exportneutrality）之敘述，何者正確？', '["對境外投資者課以較高稅率將違反該項中立性原則", "可透過來源地課稅制度（sourcetaxation）達成", "對境外所得免稅可達成該項中立性原則", "國外已納稅負於國內扣抵可符合該項中立性原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00357', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '關於政府間財政移轉的方式，下列何種補助方式較類似於稅收分成（revenuesharing）？', '["無條件", "有條件無配合款", "有條件有限額配合款", "有條件無限額配合款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00358', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '某甲某年之薪資所得新臺幣（下同）20,000元，存款利息1,000元，領取政府一個月失業津貼 2,000元，已實現資本損失1,500元，自用住宅未實現資本增益及設算租金所得30,000元。依據 海格-西蒙士（Haig-Simons）提出的全涵所得（comprehensiveincome）定義，某甲當年度全涵所 得金額為何？', '["19,500元", "21,000元", "21,500元", "51,500元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00359', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-f6c431ec', 'sub-retired-d0d1b9a2-06', NULL, 'single_choice', '若線性累進所得稅：T＝t(Y－E)，T為稅額，t為稅率，Y為家戶所得額，Y≦E時，T=0；負所 得稅：T＝t(Y－E)，當Y>E時，t為稅率，T為稅額，Y≦E時，t為補貼率，T為補貼額。下列 有關以上兩稅制之比較，何者錯誤？', '["當Y>E時，線性累進所得稅較可能打擊勞動供給", "當Y>E時，兩稅制均針對其所得淨額課稅", "當Y<E時，兩稅制之所得效果不同", "當Y<E時，線性累進所得稅制下繳納稅負為零，負所得稅制下會獲得補貼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "9dad19031d0c", "answer_pdf_sha1": "0b8bada5e8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "2005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
